63: FilterConfig::FilterConfig(const envoy::extensions::filters::http::ext_authz::v3::ExtAuthz& config,
64:                            Stats::Scope& scope, const std::string& stats_prefix,
65:                            Server::Configuration::ServerFactoryContext& factory_context)
66:     : allow_partial_message_(config.with_request_body().allow_partial_message()),
67:       failure_mode_allow_(config.failure_mode_allow()),
68:       failure_mode_allow_header_add_(config.failure_mode_allow_header_add()),
69:       clear_route_cache_(config.clear_route_cache()),
70:       max_request_bytes_(config.with_request_body().max_request_bytes()),
71: 
72:       // `pack_as_bytes_` should be true when configured with the HTTP service because there is no
73:       // difference to where the body is written in http requests, and a value of false here will
74:       // cause non UTF-8 body content to be changed when it doesn't need to.
75:       pack_as_bytes_(config.has_http_service() || config.with_request_body().pack_as_bytes()),
76: 
77:       encode_raw_headers_(config.encode_raw_headers()),
78: 
79:       status_on_error_(toErrorCode(config.status_on_error().code())),
80:       validate_mutations_(config.validate_mutations()), scope_(scope),
81:       decoder_header_mutation_checker_(
82:           config.has_decoder_header_mutation_rules()
83:               ? absl::optional<Filters::Common::MutationRules::Checker>(
84:                     Filters::Common::MutationRules::Checker(config.decoder_header_mutation_rules(),
85:                                                             factory_context.regexEngine()))
86:               : absl::nullopt),
87:       enable_dynamic_metadata_ingestion_(
88:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, enable_dynamic_metadata_ingestion, true)),
89:       runtime_(factory_context.runtime()), http_context_(factory_context.httpContext()),
90:       filter_enabled_(config.has_filter_enabled()
91:                           ? absl::optional<Runtime::FractionalPercent>(
92:                                 Runtime::FractionalPercent(config.filter_enabled(), runtime_))
93:                           : absl::nullopt),
94:       filter_enabled_metadata_(
95:           config.has_filter_enabled_metadata()
96:               ? absl::optional<Matchers::MetadataMatcher>(
97:                     Matchers::MetadataMatcher(config.filter_enabled_metadata(), factory_context))
98:               : absl::nullopt),
99:       deny_at_disable_(config.has_deny_at_disable()
100:                            ? absl::optional<Runtime::FeatureFlag>(
101:                                  Runtime::FeatureFlag(config.deny_at_disable(), runtime_))
102:                            : absl::nullopt),
103:       pool_(scope_.symbolTable()),
104:       metadata_context_namespaces_(config.metadata_context_namespaces().begin(),
105:                                    config.metadata_context_namespaces().end()),
106:       typed_metadata_context_namespaces_(config.typed_metadata_context_namespaces().begin(),
107:                                          config.typed_metadata_context_namespaces().end()),
108:       route_metadata_context_namespaces_(config.route_metadata_context_namespaces().begin(),
109:                                          config.route_metadata_context_namespaces().end()),
110:       route_typed_metadata_context_namespaces_(
111:           config.route_typed_metadata_context_namespaces().begin(),
112:           config.route_typed_metadata_context_namespaces().end()),
113:       include_peer_certificate_(config.include_peer_certificate()),
114:       include_tls_session_(config.include_tls_session()),
115:       charge_cluster_response_stats_(
116:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, charge_cluster_response_stats, true)),
117:       stats_(generateStats(stats_prefix, config.stat_prefix(), scope)),
118:       ext_authz_ok_(pool_.add(createPoolStatName(config.stat_prefix(), "ok"))),
119:       ext_authz_denied_(pool_.add(createPoolStatName(config.stat_prefix(), "denied"))),
120:       ext_authz_error_(pool_.add(createPoolStatName(config.stat_prefix(), "error"))),
121:       ext_authz_invalid_(pool_.add(createPoolStatName(config.stat_prefix(), "invalid"))),
122:       ext_authz_failure_mode_allowed_(
123:           pool_.add(createPoolStatName(config.stat_prefix(), "failure_mode_allowed"))) {
124:   auto bootstrap = factory_context.bootstrap();
125:   auto labels_key_it =
126:       bootstrap.node().metadata().fields().find(config.bootstrap_metadata_labels_key());
127:   if (labels_key_it != bootstrap.node().metadata().fields().end()) {
128:     for (const auto& labels_it : labels_key_it->second.struct_value().fields()) {
129:       destination_labels_[labels_it.first] = labels_it.second.string_value();
130:     }
131:   }
132: 
133:   if (config.has_allowed_headers() &&
134:       config.http_service().authorization_request().has_allowed_headers()) {
135:     throw EnvoyException("Invalid duplicate configuration for allowed_headers.");
136:   }
137: 
138:   // An unset request_headers_matchers_ means that all client request headers are allowed through
139:   // to the authz server; this is to preserve backwards compatibility when introducing
140:   // allowlisting of request headers for gRPC authz servers. Pre-existing support is for
141:   // HTTP authz servers only and defaults to blocking all but a few headers (i.e. Authorization,
142:   // Method, Path and Host).
143:   if (config.has_grpc_service() && config.has_allowed_headers()) {
144:     allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
145:         config.allowed_headers(), false, factory_context);
146:   } else if (config.has_http_service()) {
147:     if (config.http_service().authorization_request().has_allowed_headers()) {
148:       allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
149:           config.http_service().authorization_request().allowed_headers(), true, factory_context);
150:     } else {
151:       allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
152:           config.allowed_headers(), true, factory_context);
153:     }
154:   }
155:   if (config.has_disallowed_headers()) {
156:     disallowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
157:         config.disallowed_headers(), false, factory_context);
158:   }
